```xml
<dependency>
    <groupId>org.bytedeco</groupId>
    <artifactId>javacv</artifactId>
    <version>1.5.6</version>
</dependency>
<dependency>
    <groupId>org.bytedeco</groupId>
    <artifactId>javacpp</artifactId>
    <version>1.5.6</version>
</dependency>
```

其中 `WebSocketClient` 类需要根据具体项目中使用的WebSocket库进行自定义。

下面是一个使用JavaCV显示图片的WebSocket服务端代码示例：

```java
import java.io.IOException;
import java.nio.ByteBuffer;
import java.util.Collections;
import java.util.HashSet;
import java.util.Set;

import org.apache.commons.io.IOUtils;
import org.eclipse.jetty.websocket.api.Session;
import org.eclipse.jetty.websocket.api.StatusCode;
import org.eclipse.jetty.websocket.api.annotations.OnWebSocketClose;
import org.eclipse.jetty.websocket.api.annotations.OnWebSocketConnect;
import org.eclipse.jetty.websocket.api.annotations.OnWebSocketError;
import org.eclipse.jetty.websocket.api.annotations.OnWebSocketMessage;
import org.eclipse.jetty.websocket.api.annotations.WebSocket;
import org.eclipse.jetty.websocket.server.WebSocketHandler;
import org.eclipse.jetty.websocket.server.WebSocketServerFactory;
import org.eclipse.jetty.websocket.servlet.WebSocketServletFactory;
import org.bytedeco.javacpp.opencv_core.*;
import org.bytedeco.javacv.Java2DFrameConverter;
import org.bytedeco.javacv.OpenCVFrameConverter;

import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.ByteArrayOutputStream;

@WebSocket
public class WebsocketImageServer extends WebSocketHandler {
    private Set<Session> sessions = Collections.synchronizedSet(new HashSet<>());

    @Override
    public void configure(WebSocketServletFactory factory) {
        factory.setCreator((req, rsp) -> new WebsocketImageServer());
    }

    @Override
    public void configure(WebSocketServerFactory factory) {
        factory.setCreator((req, rsp) -> new WebsocketImageServer());
    }

    @OnWebSocketConnect
    public void onConnect(Session session) {
        System.out.println("Websocket connected: " + session.getRemoteAddress());
        sessions.add(session);
    }

    @OnWebSocketClose
    public void onClose(Session session, int statusCode, String reason) {
        System.out.println("Websocket disconnected: " + session.getRemoteAddress());
        sessions.remove(session);
    }

    @OnWebSocketMessage
    public void onMessage(Session session, byte[] imageData, int offset, int length) throws IOException {
        // 将图片数据解码为BufferedImage对象
        BufferedImage image = ImageIO.read(IOUtils.toInputStream(ByteBuffer.wrap(imageData).array()));
        // 将BufferedImage对象转换为OpenCV Mat对象并显示
        if (image != null) {
            // 创建帧转换器和Mat对象
            OpenCVFrameConverter.ToMat converter = new OpenCVFrameConverter.ToMat();
            Mat mat = converter.convertToMat(new Java2DFrameConverter().convert(image));
            // 转换为JPEG格式并发送给客户端
            ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
            ImageIO.write(image, "JPEG", outputStream);
            for (Session sess : sessions) {
                sess.getRemote().sendBytes(ByteBuffer.wrap(outputStream.toByteArray()));
            }
        }
    }

    @OnWebSocketError
    public void onError(Session session, Throwable error) {
        System.err.println("Websocket error: " + session.getRemoteAddress() + " - " + error.getMessage());
        session.close(StatusCode.NORMAL, error.getMessage());
        sessions.remove(session);
    }

    public static void main(String[] args) {
        WebSocketServerFactory serverFactory = new WebSocketServerFactory();
        //configuring with an address is also possible
        serverFactory.setBufferSize(4096);
        serverFactory.setHandler(new WebsocketImageServer());
        org.eclipse.jetty.server.Server server = new org.eclipse.jetty.server.Server(8080);
        server.setHandler(serverFactory);
        try {
            server.start();
            server.join();
        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            server.destroy();
        }
    }

}
```

